const body = $json.body;
return [{
  json: {
    jobId: body.jobId,
    fileUrl: body.fileUrl,
    callbackUrl: body.callbackUrl,
    prompt: body.prompt || 'Phân tích dữ liệu và chỉ ra các xu hướng chính'
  }
}];

const parsed = $json;
const headers = parsed.headers || [];
const rows = parsed.rows || [];

const sampleRows = rows.slice(0, 100).map(row => {
  const obj = {};
  headers.forEach((h, i) => { obj[h] = row[i] || ''; });
  return obj;
});

const webhookData = $('Parse Webhook Body').first().json;

return [{
  json: {
    jobId: webhookData.jobId,
    callbackUrl: webhookData.callbackUrl,
    prompt: webhookData.prompt,
    headers: headers,
    sampleRows: sampleRows,
    fullData: rows
  }
}];

const headers = $json.headers;
const sampleRows = $json.sampleRows.slice(0, 5);
const prompt = $json.prompt;

const textPrompt = `Bạn là data analyst chuyên nghiệp. Phân tích schema CSV và sinh Python code dùng pandas + matplotlib.
Schema columns: ${JSON.stringify(headers)}
Sample data (first 5 rows): ${JSON.stringify(sampleRows)}
Câu hỏi phân tích: ${prompt}

Hãy trả về một JSON object (KHÔNG bọc trong markdown code block), với format chính xác:
{ "chartType": "bar|line|pie|scatter", "pythonCode": "...python code...", "analysisDescription": "...mô tả ngắn..." }`;

const payload = {
  contents: [
    {
      parts: [
        { text: textPrompt }
      ]
    }
  ],
  generationConfig: {
    maxOutputTokens: 2048,
    temperature: 0.3
  }
};

return [{ json: { geminiPayload: JSON.stringify(payload) } }];

let text = $json.candidates[0].content.parts[0].text;
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('Cannot parse Gemini response: ' + text.substring(0, 200));
  }
}

const previous = $('Format Data').first().json;
return [{
  json: {
    ...previous,
    chartType: parsed.chartType,
    pythonCode: parsed.pythonCode,
    analysisDescription: parsed.analysisDescription
  }
}];

const stats = $json.stats || {};
const analysisDesc = $('Parse Gemini JSON').first().json.analysisDescription || '';

const textPrompt = `Bạn là chuyên gia phân tích dữ liệu. Dựa vào kết quả thống kê sau đây, hãy viết một bản insights phân tích bằng tiếng Việt (3-5 đoạn văn), dễ hiểu cho người không chuyên kỹ thuật:

Kết quả thống kê: ${JSON.stringify(stats)}

Mô tả phân tích: ${analysisDesc}`;

const payload = {
  contents: [
    {
      parts: [
        { text: textPrompt }
      ]
    }
  ],
  generationConfig: {
    maxOutputTokens: 1024,
    temperature: 0.5
  }
};

return [{ json: { geminiPayload: JSON.stringify(payload) } }];

