const crypto = require('crypto');
const secret = process.env.CALLBACK_HMAC_SECRET || 'SUPER_SECRET_HMAC_KEY_123456789012345';

const jobId = $('Format Data').first().json.jobId;
const pdfUrl = $json.pdfUrl;

const payload = JSON.stringify({
  JobId: jobId,
  Status: 2,
  Progress: 100,
  CurrentStep: 'finalize',
  Message: 'Analysis Completed Successfully',
  ResultUrl: pdfUrl
});

const signature = crypto.createHmac('sha256', secret).update(payload).digest('base64');

return [{
  json: {
    CallbackUrl: $('Format Data').first().json.callbackUrl,
    PayloadString: payload,
    Signature: signature
  }
}];

let webhookData = null;
try {
  webhookData = $('Parse Webhook Body').first().json;
} catch (e) {}

if (!webhookData || !webhookData.callbackUrl) return [];

const crypto = require('crypto');
const secret = process.env.CALLBACK_HMAC_SECRET || 'SUPER_SECRET_HMAC_KEY_123456789012345';
const errorMessage = $json.execution?.error?.message || 'Unknown workflow error';

const payload = JSON.stringify({
  JobId: webhookData.jobId,
  Status: 3,
  Progress: 0,
  CurrentStep: 'error',
  Message: errorMessage,
  ResultUrl: null
});

const signature = crypto.createHmac('sha256', secret).update(payload).digest('base64');

return [{
  json: {
    CallbackUrl: webhookData.callbackUrl,
    PayloadString: payload,
    Signature: signature
  }
}];
